ницыДляОтчетов ИНАЧЕ 0 КОНЕЦ * ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) ТОГДА ДД.Количество ИНАЧЕ 0 КОНЕЦ) КАК ВключениеКоличество, СУММА(ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) ТОГДА ДД.СтоимостьБезНДС ИНАЧЕ 0 КОНЕЦ) КАК ВключениеСтоимостьБезНДС, СУММА(ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) ТОГДА ДД.НДС ИНАЧЕ 0 КОНЕЦ) КАК ВключениеНДС, СУММА(ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) ТОГДА ДД.НДСУпр ИНАЧЕ 0 КОНЕЦ) КАК ВключениеНДСУпр, СУММА(ВЫБОР КОГДА &ЕдиницыКоличества = 0 ТОГДА 1 КОГДА &ЕдиницыКоличества = 1 И АналитикаНоменклатуры.Номенклатура.КоэффициентЕдиницыДляОтчетов <> 0 ТОГДА 1 / АналитикаНоменклатуры.Номенклатура.КоэффициентЕдиницыДляОтчетов ИНАЧЕ 0 КОНЕЦ * ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) ТОГДА ДД.Количество ИНАЧЕ 0 КОНЕЦ) КАК ИсключениеКоличество, СУММА(ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) ТОГДА ДД.СтоимостьБезНДС ИНАЧЕ 0 КОНЕЦ) КАК ИсключениеСтоимостьБезНДС, СУММА(ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) ТОГДА ДД.НДС ИНАЧЕ 0 КОНЕЦ) КАК ИсключениеНДС, СУММА(ВЫБОР КОГДА ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) ТОГДА ДД.НДСУпр ИНАЧЕ 0 КОНЕЦ) КАК ИсключениеНДСУпр, СтоимостьТоваров.СтоимостьБезНДС + СтоимостьТоваров.СтоимостьДопРасходыБезНДС + СтоимостьТоваров.Трудозатраты + СтоимостьТоваров.ПостатейныеПостоянныеБезНДС + СтоимостьТоваров.ПостатейныеПеременныеБезНДС КАК ЦенаБезНДС, СтоимостьТоваров.СтоимостьРегл + СтоимостьТоваров.ДопРасходыРегл + СтоимостьТоваров.ТрудозатратыРегл + СтоимостьТоваров.ПостатейныеПостоянныеРегл + СтоимостьТоваров.ПостатейныеПеременныеРегл КАК ЦенаРегл, СтоимостьТоваров.СтоимостьУпр + СтоимостьТоваров.ДопРасходыУпр + СтоимостьТоваров.ТрудозатратыУпр + СтоимостьТоваров.ПостатейныеПостоянныеУпр + СтоимостьТоваров.ПостатейныеПеременныеУпр КАК ЦенаУпр, ВЫБОР КОГДА (СтоимостьТоваров.СтоимостьБезНДС + СтоимостьТоваров.СтоимостьДопРасходыБезНДС + СтоимостьТоваров.ПостатейныеПостоянныеБезНДС + СтоимостьТоваров.ПостатейныеПеременныеБезНДС) <> 0 ТОГДА ВЫРАЗИТЬ( (СтоимостьТоваров.Стоимость + СтоимостьТоваров.СтоимостьДопРасходы + СтоимостьТоваров.ПостатейныеПостоянныеСНДС + СтоимостьТоваров.ПостатейныеПеременныеСНДС) / (СтоимостьТоваров.СтоимостьБезНДС + СтоимостьТоваров.СтоимостьДопРасходыБезНДС + СтоимостьТоваров.ПостатейныеПостоянныеБезНДС + СтоимостьТоваров.ПостатейныеПеременныеБезНДС) - 1 КАК ЧИСЛО(28, 2)) ИНАЧЕ 0 КОНЕЦ КАК ПроцентНДС ПОМЕСТИТЬ Обороты {ВЫБРАТЬ Период, Организация.*, ХозяйственнаяОперация.*, Регистратор.*, РазделУчета.*, АналитикаУчетаНоменклатуры.*, Номенклатура.*, ЕдиницаХранения.*, ЕдиницаДляОтчетов.*, КоэффициентЕдиницыДляОтчетов, Характеристика.*, Серия.*, Склад.*, Назначение.*, НаправлениеДеятельности.*, Договор.*, ВидЗапасов.*, Подразделение.*, ГруппаФинансовогоУчета, Партия.*, АналитикаУчетаПартий.*, ВидДеятельностиНДС.*, КорВидДеятельностиНДС.*, СтатьяРасходовАктивов.*, АналитикаРасходов.*, АналитикаАктивов.*, СтатьяСписанияНДС.*, АналитикаСписанияНДС.*, ДокументПоступления.*, АналитикаФинансовогоУчета.*, ТипЗаписи.*, ВключениеКоличество, ВключениеСтоимостьБезНДС, ВключениеНДС, ВключениеНДСУпр, ИсключениеКоличество, ИсключениеСтоимостьБезНДС, ИсключениеНДС, ИсключениеНДСУпр} ИЗ РегистрНакопления.ДетализацияПартийТоваровДляНДСиУСН КАК ДД ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.КлючиАналитикиУчетаНоменклатуры КАК АналитикаНоменклатуры ПО ДД.АналитикаУчетаНоменклатуры = АналитикаНоменклатуры.Ссылка ВНУТРЕННЕЕ СОЕДИНЕНИЕ РегистрСведений.СтоимостьТоваров КАК СтоимостьТоваров ПО НАЧАЛОПЕРИОДА(ДД.Период, МЕСЯЦ) = СтоимостьТоваров.Период И ДД.Организация = СтоимостьТоваров.Организация И ДД.РазделУчета = СтоимостьТоваров.РазделУчета И ДД.ВидЗапасов = СтоимостьТоваров.ВидЗапасов И ДД.АналитикаУчетаНоменклатуры = СтоимостьТоваров.АналитикаУчетаНоменклатуры ГДЕ ДД.ВидДвижения = ЗНАЧЕНИЕ(ВидДвиженияНакопления.Расход) И ДД.ВидДеятельностиНДС <> ДД.КорВидДеятельностиНДС И ДД.КорВидДеятельностиНДС <> ЗНАЧЕНИЕ(Перечисление.ТипыНалогообложенияНДС.ПустаяСсылка) И НЕ (ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСУчитываетсяВСтоимости)) И НЕ (ДД.ВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости) И ДД.КорВидДеятельностиНДС В (&ТипыНалогообложенияНДСНеУчитываетсяВСтоимости)) {ГДЕ ДД.Период МЕЖДУ &НачалоПериода И &КонецПериода, (АналитикаНоменклатуры.Номенклатура, АналитикаНоменклатуры.Характеристика) В (ВЫБРАТЬ ОтборПоСегментуНоменклатуры.Номенклатура, ОтборПоСегментуНоменклатуры.Характеристика ИЗ ОтборПоСегментуНоменклатуры ГДЕ ОтборПоСегментуНоменклатуры.ИспользуетсяОтборПоСегментуНоменклатуры = &ИспользуетсяОтборПоСегментуНоменклатуры), АналитикаНоменклатуры.МестоХранения.* КАК Склад, АналитикаНоменклатуры.Назначение.* КАК Назначение, АналитикаНоменклатуры.Назначение.НаправлениеДеятельности.* КАК НаправлениеДеятельности, АналитикаНоменклатуры.Номенклатура.* КАК Номенклатура, АналитикаНоменклатуры.Номенклатура.ЕдиницаДляОтчетов.* КАК ЕдиницаДляОтчетов, АналитикаНоменклатуры.Номенклатура.ЕдиницаИзмерения.* КАК ЕдиницаИзмерения, АналитикаНоменклатуры.Номенклатура.КоэффициентЕдиницыДляОтчетов КАК КоэффициентЕдиницыДляОтч